import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as l}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as o,o as i,c as r,a2 as t}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Safety/cloudflare-api-token.md","filePath":"uk-UA/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),d={name:"uk-UA/Safety/cloudflare-api-token.md"};function n(p,a,u,c,h,s){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Облікові дані Cloudflare API дозволяють ImgBed очищати кеш Cloudflare CDN після змін у файлах.</p><p><img src="'+e+'" alt="Налаштування Cloudflare API Token" loading="lazy"></p><h2 id="де-це-налаштовується" tabindex="-1">Де це налаштовується <a class="header-anchor" href="#де-це-налаштовується" aria-label="Permalink to &quot;Де це налаштовується&quot;">​</a></h2><p>Відкрийте адмін-панель і перейдіть до:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Потрібно заповнити:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="що-робить-це-налаштування" tabindex="-1">Що робить це налаштування <a class="header-anchor" href="#що-робить-це-налаштування" aria-label="Permalink to &quot;Що робить це налаштування&quot;">​</a></h2><p>Cloudflare може кешувати публічні URL зображень.</p><p>Кеш прискорює доставку зображень, але після видалення, блокування, заміни або переміщення файлу старий вміст може ще деякий час залишатися видимим.</p><p>Після налаштування облікових даних Cloudflare API ImgBed намагається очистити пов&#39;язаний кеш Cloudflare, коли такі операції завершуються.</p><p>Це корисно, якщо:</p><ul><li>ви видаляєте зображення й хочете, щоб публічне посилання перестало працювати якомога швидше;</li><li>ви блокуєте зображення й хочете, щоб відвідувачі більше не бачили оригінальний файл;</li><li>ви замінюєте файл із тією самою назвою й хочете швидше показати відвідувачам нову версію;</li><li>ви переміщуєте або перейменовуєте файли й хочете швидко оновити кеш старих шляхів;</li><li>ви змінюєте правила публічного доступу й хочете швидше оновити кеш публічної галереї або random image API.</li></ul><h2 id="що-буде-якщо-залишити-порожнім" tabindex="-1">Що буде, якщо залишити порожнім <a class="header-anchor" href="#що-буде-якщо-залишити-порожнім" aria-label="Permalink to &quot;Що буде, якщо залишити порожнім&quot;">​</a></h2><p>ImgBed і далі працюватиме нормально без цього налаштування.</p><p>Єдина різниця: ImgBed не буде активно очищати кеш Cloudflare CDN. Відвідувачі можуть бачити старий вміст, доки кеш Cloudflare не завершиться природно.</p><h2 id="як-знаити-zone-id" tabindex="-1">Як знайти Zone ID <a class="header-anchor" href="#як-знаити-zone-id" aria-label="Permalink to &quot;Як знайти Zone ID&quot;">​</a></h2><p>Zone ID — це Cloudflare Zone ID сайту, який використовується вашим доменом ImgBed.</p><ol><li>Увійдіть у Cloudflare dashboard.</li><li>Відкрийте сайт, у якому знаходиться ваш домен ImgBed.</li><li>Знайдіть <code>Zone ID</code> на overview-сторінці сайту.</li><li>Скопіюйте його в поле <code>Zone ID</code> в ImgBed.</li></ol><p>Це саме Zone ID сайту, а не account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Введіть email, який використовуєте для входу в Cloudflare.</p><p>Він має відповідати API Key, який ви вкажете нижче.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Введіть Cloudflare Global API Key.</p><ol><li>Увійдіть у Cloudflare dashboard.</li><li>Відкрийте свій profile.</li><li>Перейдіть на сторінку API Tokens.</li><li>Знайдіть <code>Global API Key</code>.</li><li>Перегляньте й скопіюйте його.</li><li>Вставте його в поле <code>API Key</code> в ImgBed.</li></ol><p><img src="'+l+'" alt="Перегляд global API key" loading="lazy"></p><h2 id="коли-це-починає-працювати" tabindex="-1">Коли це починає працювати <a class="header-anchor" href="#коли-це-починає-працювати" aria-label="Permalink to &quot;Коли це починає працювати&quot;">​</a></h2><p>Після заповнення полів збережіть налаштування.</p><p>Майбутні зміни файлів автоматично намагатимуться очистити кеш Cloudflare. Минулі операції не очищаються заднім числом. Якщо файл було видалено або замінено до цього налаштування, дочекайтеся завершення кешу Cloudflare або очистьте його вручну в Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="це-обов-язково" tabindex="-1">Це обов&#39;язково? <a class="header-anchor" href="#це-обов-язково" aria-label="Permalink to &quot;Це обов&#39;язково?&quot;">​</a></h3><p>Ні.</p><p>Якщо ваш домен не використовує Cloudflare або вас не турбує затримка CDN-кешу, поле можна залишити порожнім.</p><h3 id="неправильні-облікові-дані-зламають-завантаження" tabindex="-1">Неправильні облікові дані зламають завантаження? <a class="header-anchor" href="#неправильні-облікові-дані-зламають-завантаження" aria-label="Permalink to &quot;Неправильні облікові дані зламають завантаження?&quot;">​</a></h3><p>Зазвичай ні.</p><p>Неправильні облікові дані лише завадять ImgBed очищати кеш Cloudflare. Завантаження й звичайний доступ до файлів мають працювати далі.</p><h3 id="чому-видалене-зображення-все-ще-відкривається" tabindex="-1">Чому видалене зображення все ще відкривається? <a class="header-anchor" href="#чому-видалене-зображення-все-ще-відкривається" aria-label="Permalink to &quot;Чому видалене зображення все ще відкривається?&quot;">​</a></h3><p>Найчастіша причина — Cloudflare усе ще має старий файл у кеші.</p><p>З правильними обліковими даними Cloudflare API ImgBed очищає кеш пов&#39;язаного URL під час видалення файлу.</p><h3 id="чому-після-заміни-фаилу-я-все-ще-бачу-старе-зображення" tabindex="-1">Чому після заміни файлу я все ще бачу старе зображення? <a class="header-anchor" href="#чому-після-заміни-фаилу-я-все-ще-бачу-старе-зображення" aria-label="Permalink to &quot;Чому після заміни файлу я все ще бачу старе зображення?&quot;">​</a></h3><p>Це також зазвичай спричинено CDN-кешем.</p><p>Після налаштування цього параметра ImgBed намагається очистити кеш старого URL, коли файл із тією самою назвою перезаписується.</p>',44)])])}const k=o(d,[["render",n]]);export{b as __pageData,k as default};
